@dataclass
class Dependency:
    """Represents a single Python dependency."""
    name: str
    version: str = ""
    extras: List[str] = field(default_factory=list)
    hashes: List[str] = field(default_factory=list)
    environment: str = "prod"
    source: str = "pypi"
    is_direct: bool = True

    @property
    def pinned_spec(self) -> str:
        extras_str = f"[{','.join(self.extras)}]" if self.extras else ""
        version_str = f"=={self.version}" if self.version else ""
        return f"{self.name}{extras_str}{version_str}"

    @property
    def hash_lines(self) -> str:
        if not self.hashes:
            return ""
        return " \\\n    ".join(f"--hash={h}" for h in self.hashes)

    def to_requirements_line(self) -> str:
        line = self.pinned_spec
        if self.hashes:
            line += " \\\n    " + self.hash_lines
        return line


@dataclass
class LockFileMetadata:
    """Metadata stored alongside lock files for reproducibility."""
    generated_at: str = ""
    python_version: str = ""
    platform: str = ""
    backend: str = ""
    content_hash: str = ""

    def to_header(self) -> str:
        return textwrap.dedent(f"""\
        #
        # This file is autogenerated by dependency_manager.py
        # Do not edit manually. Run `python dependency_manager.py lock` to regenerate.
        #
        # Generated at: {self.generated_at}
        # Python:       {self.python_version}
        # Platform:     {self.platform}
        # Backend:      {self.backend}
        # Content hash: {self.content_hash}
        #
        """)


@dataclass
class ProjectConfig:
    """Persisted project configuration for the dependency manager."""
    backend: str = Backend.PIP_TOOLS.value
    python_version: str = ""
    environments: List[str] = field(default_factory=lambda: ["dev", "prod", "test"])
    hash_checking: bool = True
    allow_prereleases: bool = False
    index_url: str = "https://pypi.org/simple"
    extra_index_urls: List[str] = field(default_factory=list)
    trusted_hosts: List[str] = field(default_factory=list)

    # Mapping of environment -> input file
    input_files: Dict[str, str] = field(default_factory=dict)
    # Mapping of environment -> output (lock) file
    output_files: Dict[str, str] = field(default_factory=dict)

    def save(self, path: Path = CONFIG_FILE) -> None:
        path.write_text(json.dumps(self.__dict__, indent=2) + "\n")
        logger.info("Configuration saved to %s", path)

    @classmethod
    def load(cls, path: Path = CONFIG_FILE) -> "ProjectConfig":
        if not path.exists():
            logger.warning("No config found at %s – using defaults.", path)
            return cls()
        data = json.loads(path.read_text())
        return cls(**data)


