def run_command(
    cmd: List[str],
    capture: bool = False,
    check: bool = True,
    env: Optional[Dict[str, str]] = None,
) -> subprocess.CompletedProcess:
    """Run a subprocess command with logging."""
    logger.debug("Running: %s", " ".join(cmd))
    merged_env = {**os.environ, **(env or {})}
    try:
        result = subprocess.run(
            cmd,
            capture_output=capture,
            text=True,
            check=check,
            env=merged_env,
        )
        return result
    except subprocess.CalledProcessError as exc:
        logger.error("Command failed (exit %d): %s", exc.returncode, " ".join(cmd))
        if exc.stderr:
            logger.error("stderr:\n%s", exc.stderr)
        raise


def ensure_tool_installed(tool: str) -> bool:
    """Check whether a CLI tool is available on PATH."""
    return shutil.which(tool) is not None


def compute_file_hash(path: Path) -> str:
    """SHA-256 hash of a file's contents."""
    h = hashlib.sha256()
    h.update(path.read_bytes())
    return f"sha256:{h.hexdigest()}"


def current_python_version() -> str:
    return f"{sys.version_info.major}.{sys.version_info.minor}.{sys.version_info.micro}"


def current_platform() -> str:
    import platform as _platform
    return f"{_platform.system()}-{_platform.machine()}"


def build_metadata(backend: str, content_hash: str = "") -> LockFileMetadata:
    return LockFileMetadata(
        generated_at=datetime.utcnow().isoformat() + "Z",
        python_version=current_python_version(),
        platform=current_platform(),
        backend=backend,
        content_hash=content_hash,
    )


def parse_requirements_txt(path: Path) -> List[Dependency]:
    """Parse a requirements.txt file into Dependency objects."""
    deps: List[Dependency] = []
    if not path.exists():
        return deps

    current_line = ""
    for raw_line in path.read_text().splitlines():
        stripped = raw_line.strip()
        if not stripped or stripped.startswith("#") or stripped.startswith("-"):
            # Skip blank, comment, and option lines (unless continuation)
            if current_line and not current_line.endswith("\\"):
                current_line = ""
            continue

        if current_line.endswith("\\"):
            current_line = current_line[:-1].strip() + " " + stripped
        else:
            if current_line:
                deps.append(_parse_single_requirement(current_line))
            current_line = stripped

    if current_line:
        deps.append(_parse_single_requirement(current_line))

    return deps


def _parse_single_requirement(line: str) -> Dependency:
    """Parse one (possibly multi-line-joined) requirement line."""
    hashes: List[str] = []
    hash_pattern = re.compile(r"--hash=(\S+)")
    for match in hash_pattern.finditer(line):
        hashes.append(match.group(1))
    line = hash_pattern.sub("", line).strip()

    # Handle extras
    extras: List[str] = []
    extras_match = re.search(r"\[([^\]]+)\]", line)
    if extras_match:
        extras = [e.strip() for e in extras_match.group(1).split(",")]

    # Split name==version
    parts = re.split(r"[=<>!~]=?", line, maxsplit=1)
    name = re.sub(r"\[.*\]", "", parts[0]).strip()
    version = parts[1].strip() if len(parts) > 1 else ""

    return Dependency(name=name, version=version, extras=extras, hashes=hashes)


