class PipToolsBackend:
    """
    Manages dependencies using pip-tools (pip-compile + pip-sync).

    Workflow:
        1. Maintain human-readable *.in files with loose constraints.
        2. Run pip-compile to produce fully pinned *.txt lock files with hashes.
        3. Run pip-sync to install exactly what the lock file specifies.
    """

    def __init__(self, config: ProjectConfig):
        self.config = config
        self._ensure_pip_tools()

    # -- public API ----------------------------------------------------------

    def init(self) -> None:
        """Create skeleton .in files for each environment."""
        mapping = self._env_file_mapping()
        for env_name, (in_file, _out_file) in mapping.items():
            in_path = PROJECT_ROOT / in_file
            if not in_path.exists():
                header = textwrap.dedent(f"""\
                    # {env_name} dependencies
                    # Add your top-level dependencies here (one per line).
                    # Use flexible version constraints; pip-compile will pin exact versions.
                    #
                    # Examples:
                    #   requests>=2.28,<3
                    #   django~=4.2
                    #   celery[redis]
                    #
                """)
                in_path.write_text(header)
                logger.info("Created %s", in_path)
            else:
                logger.info("Already exists: %s", in_path)

    def lock(self, env: Environment) -> None:
        """Generate / regenerate lock files for the given environment(s)."""
        envs = self._resolve_envs(env)
        mapping = self._env_file_mapping()

        for env_name in envs:
            if env_name not in mapping:
                logger.warning("No file mapping for environment '%s' – skipping.", env_name)
                continue
            in_file, out_file = mapping[env_name]
            in_path = PROJECT_ROOT / in_file
            out_path = PROJECT_ROOT / out_file

            if not in_path.exists():
                logger.warning("Input file %s does not exist – skipping.", in_path)
                continue

            logger.info("Compiling %s -> %s …", in_path.name, out_path.name)
            cmd = [
                sys.executable, "-m", "piptools", "compile",
                "--strip-extras",
                "--no-header",
                "--resolver=backtracking",
                "--output-file", str(out_path),
                str(in_path),
            ]
            if self.config.hash_checking:
                cmd.append("--generate-hashes")
            if self.config.allow_prereleases:
                cmd.append("--pre")
            if self.config.index_url:
                cmd.extend(["--index-url", self.config.index_url])
            for extra_url in self.config.extra_index_urls:
                cmd.extend(["--extra-index-url", extra_url])

            run_command(cmd)

            # Prepend metadata header
            content = out_path.read_text()
            meta = build_metadata(
                backend=Backend.PIP_TOOLS.value,
                content_hash=compute_file_hash(out_path),
            )
            out_path.write_text(meta.to_header() + content)
            logger.info("Lock file written: %s", out_path)

    def install(self, env: Environment) -> None:
        """Install dependencies from lock file(s) using pip-sync."""
        envs = self._resolve_envs(env)
        mapping = self._env_file_mapping()
        files_to_sync: List[str] = []

        for env_name in envs:
            if env_name not in mapping:
                continue
            _in_file, out_file = mapping[env_name]
            out_path = PROJECT_ROOT / out_file
            if out_path.exists():
                files_to_sync.append(str(out_path))
            else:
                logger.warning("Lock file %s not found – run `lock` first.", out_path)

        if not files_to_sync:
            logger.error("No lock files to install.")
            return

        logger.info("Syncing: %s", ", ".join(files_to_sync))
        cmd = [sys.executable, "-m", "piptools", "sync"] + files_to_sync
        run_command(cmd)
        logger.info("Environment synchronised.")

    def update(self, package: Optional[str], env: Environment) -> None:
        """
        Update a single package (or all) and re-lock.

        If *package* is None every dependency is upgraded.
        """
        envs = self._resolve_envs(env)
        mapping = self._env_file_mapping()

        for env_name in envs:
            if env_name not in mapping:
                continue
            in_file, out_file = mapping[env_name]
            in_path = PROJECT_ROOT / in_file
            out_path = PROJECT_ROOT / out_file

            if not in_path.exists():
                continue

            logger.info("Updating %s for [%s] …", package or "ALL packages", env_name)
            cmd = [
                sys.executable, "-m", "piptools", "compile",
                "--strip-extras",
                "--no-header",
                "--resolver=backtracking",
                "--output-file", str(out_path),
            ]
            if package:
                cmd.extend(["--upgrade-package", package])
            else:
                cmd.append("--upgrade")